using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Tarefa #8 — Sequência "Novo Animal Desbloqueado": overlay (CanvasGroup,
/// Screen Space - Overlay) mostrado quando <see cref="PlayerProgress.AnimalUnlocked"/>
/// dispara pela primeira vez para uma forma (FreeAnimal — resgate de animais).
///
/// - UI: banner central com ilustração (AnimalFormData.unlockArtwork, ou
///   'icon' se vazio), nome da forma (displayName) e o texto fixo
///   "NOVO ANIMAL DESBLOQUEADO!".
/// - Música: toca AnimalFormData.unlockFanfare (ou "defaultFanfare" se vazio)
///   via AudioManager.PlaySE, sem substituir o BGM da área (mesmo padrão de
///   MissionCompleteUI — sting curto "no meio do jogo normal").
/// - Animação: se AnimalFormData.unlockCelebrationTrigger não estiver vazio,
///   dispara esse trigger no Animator do player (GameObject com tag
///   "Player") — animação de celebração curta.
///
/// Mensagens recebidas enquanto outra está visível são colocadas numa fila e
/// mostradas em sequência (mesmo padrão de PickupPopupUI/MissionCompleteUI).
///
/// Singleton com auto-fallback (funciona mesmo sem UI montada, apenas sem
/// mostrar nada — música e animação continuam a funcionar).
///
/// Montagem no Editor:
/// - Canvas (Screen Space - Overlay) com um "panelRoot" (painel central) +
///   "canvasGroup" no mesmo GameObject.
/// - "artworkImage" (Image, opcional): ilustração/ícone da forma.
/// - "titleText" (TMP_Text, opcional): "NOVO ANIMAL DESBLOQUEADO!"/defaultTitle.
/// - "nameText" (TMP_Text): AnimalFormData.displayName.
/// </summary>
public class NewAnimalUnlockedUI : MonoBehaviour
{
    public static NewAnimalUnlockedUI Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private Image artworkImage;
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private TMP_Text nameText;

    [Header("Texto Padrão")]
    [SerializeField] private string defaultTitle = "NOVO ANIMAL DESBLOQUEADO!";

    [Header("Áudio")]
    [Tooltip("Som tocado quando a forma desbloqueada não tem 'unlockFanfare' própria (opcional). Tocado via AudioManager.PlaySE — não substitui o BGM da área.")]
    [SerializeField] private AudioClip defaultFanfare;

    [Header("Transição")]
    [Tooltip("Duração do fade in/out, em segundos.")]
    [SerializeField] private float fadeDuration = 0.3f;

    [Tooltip("Tempo (s) com o banner totalmente visível, sem contar o fade.")]
    [SerializeField] private float holdDuration = 3f;

    private bool isAutoFallback;
    private bool isShowing;
    private readonly Queue<AnimalFormData> _queue = new Queue<AnimalFormData>();

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null) canvasGroup.alpha = 0f;
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(NewAnimalUnlockedUI) + " (Fallback)");
        var instance = go.AddComponent<NewAnimalUnlockedUI>();
        instance.isAutoFallback = true;
    }

    /// <summary>
    /// Mostra a sequência "Novo Animal Desbloqueado" para "form": banner +
    /// fanfarra + animação de celebração do player. Se já houver um banner
    /// visível, esta forma é colocada na fila e mostrada a seguir. Chamado
    /// automaticamente por <see cref="PlayerProgress.AnimalUnlocked"/>, mas
    /// pode também ser chamado directamente se necessário.
    /// </summary>
    public void Show(AnimalFormData form)
    {
        if (form == null) return;

        _queue.Enqueue(form);
        if (!isShowing) StartCoroutine(ShowQueueRoutine());
    }

    private IEnumerator ShowQueueRoutine()
    {
        isShowing = true;

        while (_queue.Count > 0)
        {
            var form = _queue.Dequeue();

            PlayCelebration(form);

            if (titleText != null) titleText.text = defaultTitle;
            if (nameText != null) nameText.text = form.displayName;

            if (artworkImage != null)
            {
                var sprite = form.unlockArtwork != null ? form.unlockArtwork : form.icon;
                artworkImage.sprite = sprite;
                artworkImage.gameObject.SetActive(sprite != null);
            }

            // Sem UI montada (instância "Fallback" auto-criada sem montagem no
            // Editor) — apenas espera (mantém o espaçamento entre mensagens),
            // sem overlay. Áudio/animação acima já foram disparados.
            if (canvasGroup == null)
            {
                yield return WaitUnscaled(holdDuration);
                continue;
            }

            if (panelRoot != null) panelRoot.SetActive(true);

            yield return FadeRoutine(0f, 1f);
            yield return WaitUnscaled(holdDuration);
            yield return FadeRoutine(1f, 0f);

            if (panelRoot != null) panelRoot.SetActive(false);
        }

        isShowing = false;
    }

    /// <summary>Toca a fanfarra (PlaySE) e dispara a animação de celebração no Animator do player.</summary>
    private void PlayCelebration(AnimalFormData form)
    {
        if (AudioManager.Instance != null)
        {
            if (form.unlockFanfare != null) AudioManager.Instance.PlaySE(form.unlockFanfare);
            else if (defaultFanfare != null) AudioManager.Instance.PlaySE(defaultFanfare);
        }

        if (!string.IsNullOrEmpty(form.unlockCelebrationTrigger))
        {
            var playerT = PlayerLocator.Find();
            var anim = playerT != null ? playerT.GetComponent<Animator>() : null;
            anim?.SetTrigger(form.unlockCelebrationTrigger);
        }
    }

    private IEnumerator WaitUnscaled(float duration)
    {
        float t = 0f;
        while (t < duration)
        {
            t += Time.unscaledDeltaTime;
            yield return null;
        }
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;

        canvasGroup.alpha = from;

        if (fadeDuration <= 0f)
        {
            canvasGroup.alpha = to;
            yield break;
        }

        float t = 0f;
        while (t < fadeDuration)
        {
            t += Time.unscaledDeltaTime;
            canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        canvasGroup.alpha = to;
    }
}
